"use client";

import { Card, CardFooter } from "@/components/ui/card";
import EditorToolbar from "@/registry/new-york/editor/toolbar";
import EditorBody from "@/registry/new-york/editor/editor-body";
import { Button } from "@/components/ui/button";
import { useEditorState } from "@/registry/new-york/editor/use-editor-state";
import { useTextFormatting } from "@/registry/new-york/editor/use-text-formatting";
import { useState } from "react";
import DeleteButton from "@/registry/new-york/editor/delete-button";

export default function MainEditor() {
  const editor = useEditorState();
  const formatting = useTextFormatting(editor.editorRef);
  const [isPreviewMode, setIsPreviewMode] = useState(false);

  const togglePreviewMode = () => {
    setIsPreviewMode(!isPreviewMode);
  };

  return (
    <Card className="w-full">
      <EditorToolbar
        editorRef={editor.editorRef}
        fontFamily={editor.fontFamily}
        setFont={editor.setFont}
        canUndo={editor.canUndo}
        canRedo={editor.canRedo}
        onUndo={editor.undo}
        onRedo={editor.redo}
        onBold={() => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
          }
          editor.toggleFormat("bold");
        }}
        onItalic={() => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
          }
          editor.toggleFormat("italic");
        }}
        onUnderline={() => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
          }
          editor.toggleFormat("underline");
        }}
        onHeading={(heading: "h1" | "h2") => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
          }
          editor.applyFormat(heading);
        }}
        onBulletList={() => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
            document.execCommand("insertUnorderedList");
            editor.updateContent(editor.editorRef.current.innerHTML);
          }
        }}
        onNumberList={() => {
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
            document.execCommand("insertOrderedList");
            editor.updateContent(editor.editorRef.current.innerHTML);
          }
        }}
        onInsertLink={() => {
          // LinkPrompt handles the link insertion, we just need to update content
          if (editor.editorRef.current) {
            editor.editorRef.current.focus();
            editor.updateContent(editor.editorRef.current.innerHTML);
          }
        }}
        onInsertImage={() => {
          const url = prompt("Enter the image URL:");
          if (url && editor.editorRef.current) {
            editor.editorRef.current.focus();
            document.execCommand("insertImage", false, url);
            editor.updateContent(editor.editorRef.current.innerHTML);
          }
        }}
        activeFormats={formatting.activeFormats}
        isPreviewMode={isPreviewMode}
        onTogglePreview={togglePreviewMode}
      />
      <EditorBody
        editorRef={editor.editorRef}
        fontFamily={editor.fontFamily}
        onInput={editor.handleInput}
        onKeyDown={editor.handleKeyDown}
        onUpdateFormats={formatting.updateActiveFormats}
        isPreviewMode={isPreviewMode}
      />
      <CardFooter className="gap-1">
        <Button size={"sm"}>Save</Button>
        <DeleteButton size={"sm"} />
      </CardFooter>
    </Card>
  );
}

"use client";

import { CardContent } from "@/components/ui/card";
import { getFontClass, type FontFamily } from "@/registry/new-york/editor/fonts";
import { useEffect, useState } from "react";

interface EditorBodyProps {
  editorRef: React.RefObject<HTMLDivElement>;
  fontFamily: FontFamily;
  onInput: (e: React.FormEvent<HTMLDivElement>) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => void;
  onUpdateFormats: () => void;
  isPreviewMode: boolean;
}

export default function EditorBody({
  editorRef,
  fontFamily,
  onInput,
  onKeyDown,
  onUpdateFormats,
  isPreviewMode,
}: EditorBodyProps) {
  const fontClass = getFontClass(fontFamily);
  const [isEmpty, setIsEmpty] = useState(true);

  // Initialize editor with empty state
  useEffect(() => {
    if (editorRef.current && !editorRef.current.innerHTML) {
      editorRef.current.innerHTML = "";
    }
  }, [editorRef]);

  const handleMouseUp = () => {
    onUpdateFormats();
  };

  const handleKeyUp = () => {
    onUpdateFormats();
  };

  const handleInput = (e: React.FormEvent<HTMLDivElement>) => {
    // Check if editor is empty by checking innerText
    const element = e.currentTarget;
    const text = element.innerText.trim();
    setIsEmpty(text === "");

    // Call parent's onInput handler
    onInput(e);
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Roboto:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Lato:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Noto+Sans:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Funnel+Display:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Pacifico&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Comic+Neue:wght@400;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Serif:wght@400;500;700&display=swap');

        .editor-container {
          min-height: 300px;
          padding: 16px;
          transition: all 0.2s;
          word-wrap: break-word;
          overflow-wrap: break-word;
          line-height: 1.6;
          font-size: 1rem;
          position: relative;
        }

        /* Placeholder styling */
        .editor-container.is-empty::before {
          content: "Start writing your stories...";
          color: #9ca3af;
          font-style: italic;
          pointer-events: none;
          position: absolute;
          top: 16px;
          left: 16px;
        }

        .editor-container:focus {
          outline: none;
        }

        .editor-container.editor-font-default {
          font-family: ui-sans-serif, system-ui, sans-serif;
        }

        .editor-container.editor-font-roboto {
          font-family: 'Roboto', sans-serif;
        }

        .editor-container.editor-font-montserrat {
          font-family: 'Montserrat', sans-serif;
        }

        .editor-container.editor-font-lato {
          font-family: 'Lato', sans-serif;
        }

        .editor-container.editor-font-noto-sans {
          font-family: 'Noto Sans', sans-serif;
        }

        .editor-container.editor-font-funnel-display {
          font-family: 'Funnel Display', serif;
        }

        .editor-container.editor-font-pacifico {
          font-family: 'Pacifico', cursive;
        }

        .editor-container.editor-font-comic-neue {
          font-family: 'Comic Neue', cursive;
        }

        .editor-container.editor-font-ibm-plex-sans {
          font-family: 'IBM Plex Sans', sans-serif;
        }

        .editor-container.editor-font-ibm-plex-serif {
          font-family: 'IBM Plex Serif', serif;
        }

        .editor-container h1,
        .editor-container h2,
        .editor-container h3 {
          margin: 0.5em 0;
          font-weight: 600;
        }

        .editor-container h1 {
          font-size: 1.5em;
        }

        .editor-container h2 {
          font-size: 1.25em;
        }

        .editor-container h3 {
          font-size: 1.125em;
        }

        .editor-container p {
          margin: 0.875rem 0;
        }

        .editor-container ul {
          list-style-type: disc;
        }

        .editor-container ol {
          list-style-type: decimal;
        }

        .editor-container ul,
        .editor-container ol {
          margin: 0.5em 0;
          padding-left: 2em;
        }

        .editor-container li {
          margin: 0.25em 0;
        }

        .editor-container a {
          color: #3b82f6;
          text-decoration: underline;
          cursor: pointer;
          target: "_blank"
        }

        .editor-container img {
          max-width: 100%;
          height: auto;
          margin: 0.5em 0;
        }
      `}</style>

      <CardContent className={`p-0 border ${isPreviewMode && "border-none"}`}>
        <div
          ref={editorRef}
          className={`editor-container ${fontClass} ${
            isEmpty ? "is-empty" : ""
          } ${isPreviewMode ? "preview-mode" : ""}`}
          contentEditable={!isPreviewMode}
          suppressContentEditableWarning
          onInput={handleInput}
          onKeyDown={onKeyDown}
          onMouseUp={handleMouseUp}
          onKeyUp={handleKeyUp}
          role={isPreviewMode ? "region" : "textbox"}
          aria-label={isPreviewMode ? "Content preview" : "Text editor"}
        />
      </CardContent>
    </>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { ButtonGroup } from "@/components/ui/button-group";
import { CardHeader } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import LinkPrompt from "@/registry/new-york/editor/link-prompt";
import {
  ArrowUUpLeftIcon,
  ArrowUUpRightIcon,
  EyeIcon,
  ImageIcon,
  LinkIcon,
  ListBulletsIcon,
  ListNumbersIcon,
  TextBolderIcon,
  TextHOneIcon,
  TextHTwoIcon,
  TextItalicIcon,
  TextUnderlineIcon,
} from "@phosphor-icons/react";
import { FONT_DEFINITIONS, type FontFamily } from "@/registry/new-york/editor/fonts";

interface EditorToolbarProps {
  editorRef: React.RefObject<HTMLDivElement>;
  fontFamily: FontFamily;
  setFont: (font: FontFamily) => void;
  canUndo: boolean;
  canRedo: boolean;
  onUndo: () => void;
  onRedo: () => void;
  onBold: () => void;
  onItalic: () => void;
  onUnderline: () => void;
  onHeading: (heading: "h1" | "h2") => void;
  onBulletList: () => void;
  onNumberList: () => void;
  onInsertLink: () => void;
  onInsertImage: () => void;
  activeFormats: {
    bold: boolean;
    italic: boolean;
    underline: boolean;
    h1: boolean;
    h2: boolean;
    bulletList: boolean;
    numberList: boolean;
  };
  isPreviewMode: boolean;
  onTogglePreview: () => void;
}

export default function EditorToolbar({
  fontFamily,
  setFont,
  canUndo,
  canRedo,
  onUndo,
  onRedo,
  onBold,
  onItalic,
  onUnderline,
  onHeading,
  onBulletList,
  onNumberList,
  onInsertLink,
  onInsertImage,
  activeFormats,
  isPreviewMode,
  onTogglePreview,
}: EditorToolbarProps) {
  const handleHeadingChange = (value: string) => {
    if (value === "h1") {
      onHeading("h1");
    } else if (value === "h2") {
      onHeading("h2");
    }
  };

  const handleListChange = (value: string) => {
    if (value === "bulletList") {
      onBulletList();
    } else if (value === "numberList") {
      onNumberList();
    }
  };

  const textFormatValues: string[] = [];
  if (activeFormats.bold) textFormatValues.push("bold");
  if (activeFormats.italic) textFormatValues.push("italic");
  if (activeFormats.underline) textFormatValues.push("underline");

  return (
    <TooltipProvider>
      <CardHeader className="flex items-center gap-2 flex-wrap">
        {/* Text Formatting Group */}
        <ToggleGroup
          variant="outline"
          type="multiple"
          size="sm"
          value={textFormatValues}
        >
          <ToggleGroupItem
            value="bold"
            aria-label="Toggle bold"
            onClick={onBold}
            title="Bold (Ctrl+B)"
          >
            <TextBolderIcon />
          </ToggleGroupItem>
          <ToggleGroupItem
            value="italic"
            aria-label="Toggle italic"
            onClick={onItalic}
            title="Italic (Ctrl+I)"
          >
            <TextItalicIcon />
          </ToggleGroupItem>
          <ToggleGroupItem
            value="underline"
            aria-label="Toggle underline"
            onClick={onUnderline}
            title="Underline (Ctrl+U)"
          >
            <TextUnderlineIcon />
          </ToggleGroupItem>
        </ToggleGroup>

        {/* Heading Group */}
        <ToggleGroup
          variant="outline"
          size="sm"
          type="single"
          value={activeFormats.h1 ? "h1" : activeFormats.h2 ? "h2" : ""}
          onValueChange={handleHeadingChange}
        >
          <ToggleGroupItem
            value="h1"
            aria-label="Toggle heading one"
            title="Heading 1"
          >
            <TextHOneIcon />
          </ToggleGroupItem>
          <ToggleGroupItem
            value="h2"
            aria-label="Toggle heading two"
            title="Heading 2"
          >
            <TextHTwoIcon />
          </ToggleGroupItem>
        </ToggleGroup>

        {/* List Group */}
        <ToggleGroup
          variant="outline"
          size="sm"
          type="single"
          value={
            activeFormats.bulletList
              ? "bulletList"
              : activeFormats.numberList
                ? "numberList"
                : ""
          }
          onValueChange={handleListChange}
        >
          <ToggleGroupItem
            value="bulletList"
            aria-label="Toggle bullet list"
            title="Bullet List"
          >
            <ListBulletsIcon />
          </ToggleGroupItem>
          <ToggleGroupItem
            value="numberList"
            aria-label="Toggle number list"
            title="Numbered List"
          >
            <ListNumbersIcon />
          </ToggleGroupItem>
        </ToggleGroup>

        {/* Link and Image Group */}
        <ToggleGroup variant="outline" size="sm" type="single" value="">
          <LinkPrompt onSubmit={onInsertLink}>
            <ToggleGroupItem
              value="link"
              aria-label="Insert link"
              title="Insert Link"
            >
              <LinkIcon />
            </ToggleGroupItem>
          </LinkPrompt>
          <ToggleGroupItem
            value="image"
            aria-label="Insert image"
            onClick={onInsertImage}
            title="Insert Image"
          >
            <ImageIcon />
          </ToggleGroupItem>
        </ToggleGroup>

        {/* Font Selector */}
        <Select
          value={fontFamily}
          onValueChange={(value) => setFont(value as FontFamily)}
        >
          <SelectTrigger size="sm" className="w-40">
            <SelectValue placeholder="Select font" />
          </SelectTrigger>
          <SelectContent>
            {Object.entries(FONT_DEFINITIONS).map(([key, value]) => (
              <SelectItem key={key} value={key}>
                {value.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Undo/Redo Group */}
        <ButtonGroup>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                size="icon-sm"
                variant="outline"
                aria-label="Undo"
                onClick={onUndo}
                disabled={!canUndo}
              >
                <ArrowUUpLeftIcon />
              </Button>
            </TooltipTrigger>
            <TooltipContent>Undo (Ctrl+Z)</TooltipContent>
          </Tooltip>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                size="icon-sm"
                variant="outline"
                aria-label="Redo"
                onClick={onRedo}
                disabled={!canRedo}
              >
                <ArrowUUpRightIcon />
              </Button>
            </TooltipTrigger>
            <TooltipContent>Redo (Ctrl+Y)</TooltipContent>
          </Tooltip>
        </ButtonGroup>

        {/* Preview Mode */}
        <ButtonGroup>
          <ToggleGroup
            type="single"
            size="sm"
            variant="outline"
            value={isPreviewMode ? "preview" : ""}
          >
            <ToggleGroupItem
              value="preview"
              aria-label="Toggle preview mode"
              onClick={onTogglePreview}
              title="Preview Mode"
            >
              <EyeIcon />
            </ToggleGroupItem>
          </ToggleGroup>
        </ButtonGroup>
      </CardHeader>
    </TooltipProvider>
  );
}

import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { TrashIcon } from "@phosphor-icons/react/dist/ssr";

type DeleteButtonProps = {
  iconOnly?: boolean;
  size?: React.ComponentProps<typeof Button>["size"];
  title?: React.ReactNode;
  description?: React.ReactNode;
  deleteText?: React.ReactNode;
  cancelText?: React.ReactNode;
};

export default function DeleteButton({
  iconOnly = false,
  size,
  title = "Are you sure?",
  description = "This action permanently deletes the link and its associated data. If you may need it later, consider disabling the link instead.",
  deleteText = "Delete",
  cancelText = "Cancel",
}: DeleteButtonProps) {
  return (
    <AlertDialog>
      <AlertDialogTrigger asChild>
        <Button
          variant={"destructive"}
          size={size ?? (iconOnly ? "icon" : "default")}
          aria-label="Delete"
        >
          <TrashIcon />
          {!iconOnly ? "Delete" : null}
        </Button>
      </AlertDialogTrigger>
      <AlertDialogContent size="sm">
        <AlertDialogHeader>
          <AlertDialogTitle>{title}</AlertDialogTitle>
          <AlertDialogDescription>{description}</AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>{cancelText}</AlertDialogCancel>
          <AlertDialogAction variant={"destructive"}>
            {deleteText}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
} from "@/components/ui/input-group";
import { LinkIcon } from "@phosphor-icons/react";
import { useState, KeyboardEvent, useRef } from "react";

interface LinkPromptProps {
  children: React.ReactElement;
  onSubmit: () => void;
}

export default function LinkPrompt({ children, onSubmit }: LinkPromptProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [url, setUrl] = useState("");
  const savedSelectionRef = useRef<Range | null>(null);

  const saveSelection = () => {
    const selection = window.getSelection();
    if (selection && selection.rangeCount > 0) {
      savedSelectionRef.current = selection.getRangeAt(0).cloneRange();
    }
  };

  const restoreSelection = () => {
    const selection = window.getSelection();
    if (selection && savedSelectionRef.current) {
      selection.removeAllRanges();
      selection.addRange(savedSelectionRef.current);
    }
  };

  const handleSubmit = () => {
    if (url.trim()) {
      // Restore the selection before applying the link
      restoreSelection();

      // Apply the link using execCommand
      document.execCommand("createLink", false, url.trim());

      // Reset state
      setUrl("");
      setIsOpen(false);

      // Callback to parent
      onSubmit();
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleOpenChange = (open: boolean) => {
    if (open) {
      // Save selection when opening the dialog
      saveSelection();
    }
    setIsOpen(open);
    if (!open) {
      setUrl(""); // Reset the input when the dialog closes
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
      <DialogTrigger asChild>{children}</DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Enter the URL below</DialogTitle>
          <DialogDescription>
            Make sure the link you&apos;re adding is trusted.
          </DialogDescription>
        </DialogHeader>
        <InputGroup>
          <InputGroupAddon>
            <LinkIcon />
          </InputGroupAddon>
          <InputGroupInput
            type="url"
            placeholder="https://your-link.here/"
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            onKeyDown={handleKeyDown}
            autoFocus
          />
        </InputGroup>
        <DialogFooter>
          <DialogClose asChild>
            <Button variant="outline">Cancel</Button>
          </DialogClose>
          <Button onClick={handleSubmit} disabled={!url.trim()}>
            Add
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState, useCallback, useRef } from "react";
import { FontFamily } from "@/registry/new-york/editor/fonts";
import type { FormatType } from "@/registry/new-york/editor/formatting";
import {
  applyFormat,
  removeFormat,
  toggleFormat as toggleFormatUtil,
  getEditorContent,
  setEditorContent,
} from "@/registry/new-york/editor/formatting";

export interface EditorStateType {
  content: string;
  fontFamily: FontFamily;
  selectedFormats: Set<string>;
  history: string[];
  historyIndex: number;
}

const MAX_HISTORY_SIZE = 50;
const HISTORY_DEBOUNCE_MS = 300;

export function useEditorState(initialContent: string = "") {
  const [state, setState] = useState<EditorStateType>({
    content: initialContent,
    fontFamily: "default",
    selectedFormats: new Set(),
    history: [initialContent],
    historyIndex: 0,
  });

  const editorRef = useRef<HTMLDivElement>(null!);
  const historyTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  /**
   * Add content to history with debouncing
   */
  const addToHistory = useCallback((content: string) => {
    if (historyTimeoutRef.current) {
      clearTimeout(historyTimeoutRef.current);
    }

    historyTimeoutRef.current = setTimeout(() => {
      setState((prevState) => {
        const newHistory = prevState.history.slice(
          0,
          prevState.historyIndex + 1,
        );
        newHistory.push(content);

        // Keep history size manageable
        if (newHistory.length > MAX_HISTORY_SIZE) {
          newHistory.shift();
        }

        return {
          ...prevState,
          history: newHistory,
          historyIndex: newHistory.length - 1,
        };
      });
    }, HISTORY_DEBOUNCE_MS);
  }, []);

  /**
   * Update editor content
   */
  const updateContent = useCallback(
    (newContent: string) => {
      setState((prevState) => ({
        ...prevState,
        content: newContent,
      }));
      addToHistory(newContent);
    },
    [addToHistory],
  );

  /**
   * Set font family
   */
  const setFont = useCallback((font: FontFamily) => {
    setState((prevState) => ({
      ...prevState,
      fontFamily: font,
    }));
  }, []);

  /**
   * Apply format to current selection
   */
  const applyFormatting = useCallback(
    (format: FormatType) => {
      if (editorRef.current) {
        editorRef.current.focus();
        applyFormat(format);

        // Update content after formatting
        const updatedContent = getEditorContent(editorRef.current);
        updateContent(updatedContent);

        // Update selected formats
        setState((prevState) => ({
          ...prevState,
          selectedFormats: new Set(prevState.selectedFormats).add(format),
        }));
      }
    },
    [updateContent],
  );

  /**
   * Remove format from current selection
   */
  const removeFormatting = useCallback(
    (format: FormatType) => {
      if (editorRef.current) {
        editorRef.current.focus();
        removeFormat(format);

        const updatedContent = getEditorContent(editorRef.current);
        updateContent(updatedContent);

        setState((prevState) => {
          const newFormats = new Set(prevState.selectedFormats);
          newFormats.delete(format);
          return {
            ...prevState,
            selectedFormats: newFormats,
          };
        });
      }
    },
    [updateContent],
  );

  /**
   * Toggle format on current selection
   */
  const toggleFormat = useCallback(
    (format: FormatType) => {
      if (editorRef.current) {
        editorRef.current.focus();
        toggleFormatUtil(format);

        const updatedContent = getEditorContent(editorRef.current);
        updateContent(updatedContent);

        setState((prevState) => {
          const newFormats = new Set(prevState.selectedFormats);
          if (newFormats.has(format)) {
            newFormats.delete(format);
          } else {
            newFormats.add(format);
          }
          return {
            ...prevState,
            selectedFormats: newFormats,
          };
        });
      }
    },
    [updateContent],
  );

  /**
   * Undo last action
   */
  const undo = useCallback(() => {
    setState((prevState) => {
      if (prevState.historyIndex > 0) {
        const newIndex = prevState.historyIndex - 1;
        const previousContent = prevState.history[newIndex];

        if (editorRef.current) {
          setEditorContent(editorRef.current, previousContent);
        }

        return {
          ...prevState,
          content: previousContent,
          historyIndex: newIndex,
        };
      }
      return prevState;
    });
  }, []);

  /**
   * Redo last undone action
   */
  const redo = useCallback(() => {
    setState((prevState) => {
      if (prevState.historyIndex < prevState.history.length - 1) {
        const newIndex = prevState.historyIndex + 1;
        const nextContent = prevState.history[newIndex];

        if (editorRef.current) {
          setEditorContent(editorRef.current, nextContent);
        }

        return {
          ...prevState,
          content: nextContent,
          historyIndex: newIndex,
        };
      }
      return prevState;
    });
  }, []);

  /**
   * Check if undo is available
   */
  const canUndo = state.historyIndex > 0;

  /**
   * Check if redo is available
   */
  const canRedo = state.historyIndex < state.history.length - 1;

  /**
   * Get current content
   */
  const getContent = useCallback((): string => {
    if (editorRef.current) {
      return getEditorContent(editorRef.current);
    }
    return state.content;
  }, [state.content]);

  /**
   * Get plain text content
   */
  const getPlainText = useCallback((): string => {
    if (editorRef.current) {
      return editorRef.current.innerText;
    }
    return state.content;
  }, [state.content]);

  /**
   * Handle keyboard shortcuts
   */
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "z") {
        e.preventDefault();
        undo();
      } else if (
        (e.ctrlKey || e.metaKey) &&
        (e.key === "y" || (e.shiftKey && e.key === "z"))
      ) {
        e.preventDefault();
        redo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === "b") {
        e.preventDefault();
        toggleFormat("bold");
      } else if ((e.ctrlKey || e.metaKey) && e.key === "i") {
        e.preventDefault();
        toggleFormat("italic");
      } else if ((e.ctrlKey || e.metaKey) && e.key === "u") {
        e.preventDefault();
        toggleFormat("underline");
      }
    },
    [undo, redo, toggleFormat],
  );

  /**
   * Handle content input
   */
  const handleInput = useCallback(
    (e: React.FormEvent<HTMLDivElement>) => {
      const element = e.currentTarget;
      const newContent = getEditorContent(element);
      updateContent(newContent);
    },
    [updateContent],
  );

  return {
    // State
    content: state.content,
    fontFamily: state.fontFamily,
    selectedFormats: state.selectedFormats,

    // Refs
    editorRef,

    // Methods
    updateContent,
    setFont,
    applyFormat: applyFormatting,
    removeFormat: removeFormatting,
    toggleFormat,
    undo,
    redo,
    getContent,
    getPlainText,
    handleKeyDown,
    handleInput,

    // State checks
    canUndo,
    canRedo,
  };
}

"use client";

import { useState, useCallback, useEffect, useRef } from "react";
import { isFormatActive } from "@/registry/new-york/editor/formatting";

export type FormatType =
  | "bold"
  | "italic"
  | "underline"
  | "h1"
  | "h2"
  | "bulletList"
  | "numberList";

export interface ActiveFormats {
  bold: boolean;
  italic: boolean;
  underline: boolean;
  h1: boolean;
  h2: boolean;
  bulletList: boolean;
  numberList: boolean;
}

export function useTextFormatting(editorRef: React.RefObject<HTMLDivElement>) {
  const [activeFormats, setActiveFormats] = useState<ActiveFormats>({
    bold: false,
    italic: false,
    underline: false,
    h1: false,
    h2: false,
    bulletList: false,
    numberList: false,
  });

  const selectionCheckTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  /**
   * Update active formats based on current selection
   */
  const updateActiveFormats = useCallback(() => {
    if (!editorRef.current) return;

    const selection = window.getSelection();

    // If selection is not in the editor, clear formats
    if (!selection || !editorRef.current.contains(selection.anchorNode)) {
      setActiveFormats({
        bold: false,
        italic: false,
        underline: false,
        h1: false,
        h2: false,
        bulletList: false,
        numberList: false,
      });
      return;
    }

    try {
      setActiveFormats({
        bold: isFormatActive("bold"),
        italic: isFormatActive("italic"),
        underline: isFormatActive("underline"),
        h1: isFormatActive("h1"),
        h2: isFormatActive("h2"),
        bulletList: isFormatActive("bulletList"),
        numberList: isFormatActive("numberList"),
      });
    } catch (error) {
      console.error("Error updating active formats:", error);
    }
  }, [editorRef]);

  /**
   * Debounced format update
   */
  const debouncedUpdateFormats = useCallback(() => {
    if (selectionCheckTimeoutRef.current) {
      clearTimeout(selectionCheckTimeoutRef.current);
    }

    selectionCheckTimeoutRef.current = setTimeout(() => {
      updateActiveFormats();
    }, 50);
  }, [updateActiveFormats]);

  /**
   * Handle selection change
   */
  const handleSelectionChange = useCallback(() => {
    debouncedUpdateFormats();
  }, [debouncedUpdateFormats]);

  /**
   * Handle mouse up (selection changed by mouse)
   */
  const handleMouseUp = useCallback(() => {
    updateActiveFormats();
  }, [updateActiveFormats]);

  /**
   * Handle keyboard up (selection might have changed)
   */
  const handleKeyUp = useCallback(() => {
    debouncedUpdateFormats();
  }, [debouncedUpdateFormats]);

  /**
   * Check if a specific format is active
   */
  const isFormatActiveCheck = useCallback(
    (format: FormatType): boolean => {
      return activeFormats[format];
    },
    [activeFormats],
  );

  /**
   * Get all active formats as an array
   */
  const getActiveFormatsList = useCallback((): FormatType[] => {
    return (Object.entries(activeFormats) as [FormatType, boolean][])
      .filter(([, isActive]) => isActive)
      .map(([format]) => format);
  }, [activeFormats]);

  /**
   * Setup listeners for selection changes
   */
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    // Listen for selection changes
    document.addEventListener("selectionchange", handleSelectionChange);

    // Listen for mouse and keyboard events
    editor.addEventListener("mouseup", handleMouseUp);
    editor.addEventListener("keyup", handleKeyUp);

    return () => {
      document.removeEventListener("selectionchange", handleSelectionChange);
      editor.removeEventListener("mouseup", handleMouseUp);
      editor.removeEventListener("keyup", handleKeyUp);

      if (selectionCheckTimeoutRef.current) {
        clearTimeout(selectionCheckTimeoutRef.current);
      }
    };
  }, [editorRef, handleSelectionChange, handleMouseUp, handleKeyUp]);

  return {
    activeFormats,
    isFormatActive: isFormatActiveCheck,
    getActiveFormats: getActiveFormatsList,
    updateActiveFormats,
  };
}

